```tsx web/breeze/components/CalcPage/useShoppingCartEmulator.tsx
import {
  Cloud$FinancingOption,
  Cloud$Interest,
  Cloud$Package,
  Cloud$PackageOption,
  Cloud$PackageRequestPV,
  Cloud$Product,
} from '@otovo/shared/types/cloudApi';
import { Cloud$PurchaseModelCode } from '@otovo/shared/types/cloudEnums';
import { useEffect, useReducer } from 'react';
import {
  getClosestPackage,
  isBatteryPackage,
  isEvChargerPackage,
  isPackageUpgraded as isPackageUpgradedUtil,
} from '../../lib/packageUtils';
import {
  selectPackage,
  selectPurchaseModelCode,
  toggleSurface as toggleSurfaceAction,
} from '../../stores/Interest/actions';
import transformerReducer, {
  createInitialInterestTransformerStore,
} from '../../stores/Interest/transformerReducer';
import { getMainHardwareType } from '../../stores/Interest/utils/getMainHardwareType';
import { PackageChange, ShoppingCartReturn } from './useShoppingCart';

export const getPackageRequestOptions = (
  pkg: Cloud$Package,
): Cloud$PackageOption => {
  return {
    main_hardware_type: 'pv_system',
    pv_package_size: pkg.package_size,
    pv_product_name: pkg.product_name,
    with_battery: isBatteryPackage(pkg),
    with_ev_charger: isEvChargerPackage(pkg),
    nominal_system_power: pkg.price.nominal_system_power,
    nominal_panel_power: pkg.price.equipment.panels.nominal_panel_power,
    number_of_panels: pkg.price.num_panels,
  };
};

export function getAvailablePackages(
  products: Cloud$Product[],
): Cloud$PackageOption[] {
  return products.flatMap((p) => p.packages).map(getPackageRequestOptions);
}

function getFinancingOption(
  purchaseModel: Cloud$PurchaseModelCode,
  selectedPackage: Cloud$Package,
) {
  if (!selectedPackage?.price || !purchaseModel) {
    throw new Error('Missing selected package or purchase model');
  }

  return selectedPackage.price.financing_options.reduce(
    (prev, next) => ({ ...prev, [next.purchase_model_code]: next }),
    {} as Record<Cloud$PurchaseModelCode, Cloud$FinancingOption>,
  )[purchaseModel];
}

export const useShoppingCartEmulator = (
  interest: Cloud$Interest,
): ShoppingCartReturn => {
  const [state, dispatch] = useReducer(
    transformerReducer,
    createInitialInterestTransformerStore(interest),
  );

  useEffect(() => dispatch({ type: 'UPDATE_INTEREST', interest }), [interest]);

  if (getMainHardwareType(interest) !== 'pv_system') {
    // Short circuit to avoid null pointer access (dummy response).
    return {
      availableFinancingOptions: [],
      availableShoppingCartPackages: [],
      selectedShoppingCartPackage: null,
      selectedFinancingOption: null,
      surfaceConfigurationList: [],
      isLoadingPackage: false,
      isMutatingPackageOptions: false,
      isPackageUpgraded: false,
      mainHardwareType: 'battery_system',
      changePackage: async () => {},
      toggleSurface: () => {},
      changeFinancingOption: () => {},
    };
  }

  const selectedPurchaseModel =
    state.selectedFinancingOption?.purchase_model_code;

  const availableFinancingOptions =
    state.selectedPackage?.price.financing_options.map(
      (f) => f.purchase_model_code,
    ) || [];

  const changeFinancingOption = async (
    financingOption: Cloud$PurchaseModelCode,
  ) => {
    dispatch(selectPurchaseModelCode(financingOption));
  };

  const surfaceConfigurationList = state.surfaceConfigurationList;
  const toggleSurface = (referenceId: string) => {
    dispatch(toggleSurfaceAction(referenceId));
  };

  const isPackageUpgraded = isPackageUpgradedUtil(state);

  const currentConfiguration: Cloud$PackageRequestPV = {
    main_hardware_type: 'pv_system',
    pv_product_name: state.selectedProduct.name,
    pv_package_size: state.selectedPackage.package_size,
    with_battery: isBatteryPackage(state.selectedPackage),
    with_ev_charger: isEvChargerPackage(state.selectedPackage),
  };

  const getNewConfiguration = (
    request: PackageChange,
  ): Cloud$PackageRequestPV => {
    switch (request.option) {
      case 'pv_product_name':
        return { ...currentConfiguration, pv_product_name: request.value };
      case 'pv_package_size':
        return { ...currentConfiguration, pv_package_size: request.value };
      case 'with_ev_charger': {
        const withEvCharger = request.value;
        const shouldUsePreviousPackage =
          !withEvCharger && !isEvChargerPackage(state.previousPackage);

        if (shouldUsePreviousPackage) {
          // Go back to the previous package if it is a PV package.
          // We might have selected a different package label when toggling battery off -> on.
          return getPackageRequestOptions(
            state.previousPackage,
          ) as Cloud$PackageRequestPV;
        } else {
          const currentPackageHasEvCharger =
            withEvCharger && isEvChargerPackage(state.selectedPackage);

          const newPackage = currentPackageHasEvCharger
            ? state.selectedPackage
            : getClosestPackage({
                interest,
                selectedPackage: state.selectedPackage,
                withBattery: isBatteryPackage(state.selectedPackage),
                withEvCharger,
              });
          if (newPackage) {
            // We should always get a package here, as the battery toggle will be hidden if there are no
            // battery packages.
            return getPackageRequestOptions(
              newPackage,
            ) as Cloud$PackageRequestPV;
          }
        }

        return { ...currentConfiguration, with_ev_charger: request.value };
      }
      case 'with_battery': {
        const withBattery = request.value;
        const shouldUsePreviousPackage =
          !withBattery && !isBatteryPackage(state.previousPackage);

        if (shouldUsePreviousPackage) {
          // Go back to the previous package if it is a PV package.
          // We might have selected a different package label when toggling battery off -> on.
          return getPackageRequestOptions(
            state.previousPackage,
          ) as Cloud$PackageRequestPV;
        } else {
          const currentPackageHasBattery =
            withBattery && isBatteryPackage(state.selectedPackage);

          const newPackage = currentPackageHasBattery
            ? state.selectedPackage
            : getClosestPackage({
                interest,
                selectedPackage: state.selectedPackage,
                withBattery,
                withEvCharger: isEvChargerPackage(state.selectedPackage),
              });
          if (newPackage) {
            // We should always get a package here, as the battery toggle will be hidden if there are no
            // battery packages.
            return getPackageRequestOptions(
              newPackage,
            ) as Cloud$PackageRequestPV;
          }
        }

        return { ...currentConfiguration, with_battery: request.value };
      }
    }
  };

  const changePackage = async (request: PackageChange) => {
    const newConfiguration = getNewConfiguration(request);
    dispatch(selectPackage(newConfiguration));
  };

  return {
    selectedShoppingCartPackage: state.selectedPackage,
    selectedFinancingOption: getFinancingOption(
      selectedPurchaseModel,
      state.selectedPackage,
    ),
    availableFinancingOptions,
    availableShoppingCartPackages: getAvailablePackages(
      state.interest.products,
    ),
    surfaceConfigurationList,
    isPackageUpgraded,
    changeFinancingOption,
    toggleSurface,
    changePackage,
    mainHardwareType: 'pv_system',
    isLoadingPackage: false,
    isMutatingPackageOptions: false,
  };
};
```


```ts web/breeze/components/CalcPage/useShoppingCart.ts
import {
  Cloud$Interest,
  Cloud$PackageOption,
  Cloud$PackageRequest,
  Cloud$FinancingOption,
  Cloud$Package,
} from '@otovo/shared/types/cloudApi';
import {
  Cloud$PackageSize,
  Cloud$ProductName,
  Cloud$MainHardwareType,
  Cloud$PurchaseModelCode,
} from '@otovo/shared/types/cloudEnums';
import { useEffect, useReducer, useState } from 'react';
import useSWRMutation from 'swr/mutation';
import { useSWRConfig } from 'swr';
import { SurfaceConfiguration } from '../../stores/Interest/type';
import { useShoppingCartEmulator } from './useShoppingCartEmulator';
import {
  configurationReducer,
  initialConfiguration,
} from './shoppingCartConfigurationStore';
import { getPreferredConfiguration } from './preferredPackage';
import { getMainHardwareType } from '../../stores/Interest/utils/getMainHardwareType';
import {
  getPackageCacheKey,
  generateCacheKey,
} from './utils/getPackageCacheKey';

const getPackage = async (
  url: string,
  { arg: packageRequest }: { arg: Cloud$PackageRequest },
) => {
  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(packageRequest),
  });

  if (!response.ok) {
    throw new Error(response.statusText);
  }

  const shoppingCartPackage: Cloud$Package = await response.json();

  return { shoppingCartPackage, packageRequest };
};

const getPackageOptions = async (
  url: string,
  { arg: mainHardwareType }: { arg: Cloud$MainHardwareType },
) => {
  const response = await fetch(
    `${url}?main_hardware_type=${mainHardwareType}`,
    {
      method: 'GET',
    },
  );

  if (!response.ok) {
    throw new Error(response.statusText);
  }

  const packageOptions: Cloud$PackageOption[] = await response.json();
  return packageOptions;
};

export type PackageChange =
  | {
      option: 'pv_package_size' | 'battery_package_size';
      value: Cloud$PackageSize;
    }
  | {
      option: 'pv_product_name';
      value: Cloud$ProductName;
    }
  | {
      option: 'with_ev_charger' | 'with_battery';
      value: boolean;
    };

export type ShoppingCartReturn = {
  // TODO: Remove shopping cart prefix from these
  availableShoppingCartPackages: Cloud$PackageOption[];
  selectedShoppingCartPackage: Cloud$Package;
  availableFinancingOptions: Cloud$PurchaseModelCode[];
  selectedFinancingOption: Cloud$FinancingOption;
  surfaceConfigurationList: SurfaceConfiguration[];
  isLoadingPackage: boolean;
  isMutatingPackageOptions: boolean;
  isPackageUpgraded: boolean;
  mainHardwareType: Cloud$MainHardwareType;

  changePackage: (mutation: PackageChange) => Promise<void>;
  toggleSurface: (referenceId: string) => void;
  changeFinancingOption: (purchaseModelCode: Cloud$PurchaseModelCode) => void;
};

export function useShoppingCart(interest: Cloud$Interest): ShoppingCartReturn {
  const updatePackageUrl = `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`;
  const { trigger: triggerPackageMutation } = useSWRMutation(
    updatePackageUrl,
    getPackage,
    {
      onSuccess: (data) => setNewConfiguration(data.packageRequest),
      populateCache: true,
    },
  );
  const [selectedShoppingCartPackage, setSelectedShoppingCartPackage] =
    useState(interest.active_shopping_cart_package);
  const [isLoadingPackage, setIsLoadingPackage] = useState(false);
  const { cache } = useSWRConfig();

  const [mainHardwareType] = useState<Cloud$MainHardwareType>(
    getMainHardwareType(interest),
  );
  const packageOptionsUrl = `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/package_options/`;
  const {
    trigger: triggerPackageOptions,
    data: packageOptionsData,
    isMutating: isMutatingPackageOptions,
  } = useSWRMutation(packageOptionsUrl, getPackageOptions, {});
  useEffect(() => {
    if (!triggerPackageOptions || !mainHardwareType) return;
    if (mainHardwareType !== 'battery_system') return; // TODO: remove when non-battery systems are supported
    triggerPackageOptions(mainHardwareType);
  }, [mainHardwareType, triggerPackageOptions]);

  // Cache the interest shopping cart package
  useEffect(() => {
    if (interest.active_shopping_cart_package && mainHardwareType) {
      const cacheKey = getPackageCacheKey(mainHardwareType, interest);
      const cachedData = cache.get(cacheKey);
      if (!cachedData) {
        cache.set(cacheKey, {
          data: { shoppingCartPackage: interest.active_shopping_cart_package },
        });
      }
    }
  }, [interest, cache, mainHardwareType]);

  const [{ currentConfiguration, previousConfiguration }, setNewConfiguration] =
    useReducer(configurationReducer, initialConfiguration(interest));
  const [purchaseModelCode, setPurchaseModelCode] = useState(
    interest.default_purchase_model,
  );

  // TODO: remove non-shopping cart calculations when all calculations are fetched via the shopping cart API.
  const emulatedHook = useShoppingCartEmulator(interest);
  if (mainHardwareType === 'pv_system') {
    return emulatedHook;
  }

  const availableShoppingCartPackages = packageOptionsData || [];

  const selectedFinancingOption =
    selectedShoppingCartPackage?.price.financing_options.find(
      (f) => f.purchase_model_code === purchaseModelCode,
    ) || selectedShoppingCartPackage?.price.financing_options[0];

  const availableFinancingOptions =
    selectedShoppingCartPackage?.price.financing_options.map(
      (f) => f.purchase_model_code,
    );

  const changePackage = async (packageChange: PackageChange) => {
    const preferredPackage = getPreferredConfiguration({
      packageChange,
      availableConfigurations: availableShoppingCartPackages,
      currentConfiguration,
      previousConfiguration,
    });
    const cacheKey = generateCacheKey(preferredPackage);
    const cachedData = cache.get(cacheKey);

    if (cachedData) {
      setSelectedShoppingCartPackage(cachedData.data.shoppingCartPackage);
      triggerPackageMutation(preferredPackage);
    } else {
      // Set loading state only if we are not using cached data
      setIsLoadingPackage(true);
      const response = await triggerPackageMutation(preferredPackage);
      cache.set(cacheKey, { data: response });
      setSelectedShoppingCartPackage(response.shoppingCartPackage);
      setIsLoadingPackage(false);
    }
  };

  const isPackageUpgraded =
    previousConfiguration?.main_hardware_type === 'pv_system' &&
    currentConfiguration.main_hardware_type === 'pv_system' &&
    !previousConfiguration.with_battery &&
    currentConfiguration.with_battery &&
    previousConfiguration.pv_product_name ===
      currentConfiguration.pv_product_name &&
    previousConfiguration.pv_package_size ===
      currentConfiguration.pv_package_size;

  return {
    selectedShoppingCartPackage,
    availableFinancingOptions,
    selectedFinancingOption,
    availableShoppingCartPackages,
    isLoadingPackage,
    isMutatingPackageOptions: isMutatingPackageOptions,
    mainHardwareType: mainHardwareType,
    changeFinancingOption: (p: Cloud$PurchaseModelCode) => {
      if (availableFinancingOptions.includes(p)) setPurchaseModelCode(p);
    },
    changePackage,
    toggleSurface: () => {}, // Battery has no surfaces to toggle.
    surfaceConfigurationList: [],
    isPackageUpgraded,
  };
}
```



useShoppingCart is the only consumer of the emulator. I'm cleaning up old stuff and I'm pretty sure I can remove the whole emulator thingy. Please analyze the emulator and explain on a high level what it does.
At a high level, `useShoppingCartEmulator` appears to be a legacy implementation that handles shopping cart logic specifically for PV (photovoltaic/solar panel) systems, while the main `useShoppingCart` hook handles battery systems and newer implementations.

The emulator:
1. Maintains its own state using a reducer for PV-specific configurations
2. Handles package selection, financing options, and surface configurations specifically for solar panel systems
3. Short circuits for non-PV systems (returns dummy data)
4. Provides similar interface as the main shopping cart hook but with different underlying implementation

The fact that the main `useShoppingCart` hook only uses the emulator for PV systems (`if (mainHardwareType === 'pv_system') { return emulatedHook; }`) suggests this is indeed legacy code that was probably created before the shopping cart API was fully implemented for all system types.

If you're planning to remove it, you'd need to:
1. Confirm that PV systems are now fully supported in the main shopping cart API
2. Ensure that all the PV-specific functionality in the emulator is now handled by the main hook
3. Test thoroughly that PV system configurations work correctly without the emulator

Given that this is clearly separated and only used as a fallback for PV systems, it seems like a good candidate for removal if the main shopping cart implementation now supports all system types.
so the difference is that the handlers in the main hook function differently, right? They do fetch calls, while the other one just assuumes we have all data to toggle between things are available on the client already (from the interest).
Exactly! That's a key distinction:

`useShoppingCart` (main):
- Makes API calls (`fetch`) to get packages and options
- Maintains a cache of responses
- Has loading states (`isLoadingPackage`, `isMutatingPackageOptions`)
- Actually persists changes to the backend

`useShoppingCartEmulator`:
- Works entirely with data already available in the `interest` prop
- Does all calculations and transformations client-side
- No API calls
- No real persistence
- No loading states needed (synchronous operations)

This suggests it was probably a temporary solution (hence "emulator") to handle PV systems before they were fully integrated into the shopping cart API. If PV systems are now properly supported through the API, you can safely remove the emulator and let the main hook handle everything with proper server interactions.

The emulator was essentially "faking" the shopping cart behavior by doing all calculations locally with existing data, while the main implementation actually interacts with a proper shopping cart API.
going forward we'll only support shopping cart, so that API is here to stay and there's no reason to prefix things with "shopping cart" or similar.

How batteries work is indeed different between battery and PV, so we should have two modes - but calling it an emulator is misleading. 

suggest a refactor (into however many hooks you'd like) that neatly enable us to fetch things on demand when we need that, and to toggle between things when we have all data available.

Here's a suggested refactor that makes the distinction clearer and removes the "emulator" concept:

```typescript
// usePackageSelection.ts
type PackageSelectionConfig = {
  mode: 'fetch' | 'local';
  interest: Cloud$Interest;
}

// Base hook for shared types and interfaces
function usePackageSelection({ mode, interest }: PackageSelectionConfig): PackageSelectionReturn {
  const mainHardwareType = getMainHardwareType(interest);

  // Use appropriate implementation based on mode
  if (mode === 'local') {
    return useLocalPackageSelection(interest);
  }

  return useFetchedPackageSelection(interest);
}

// For battery systems - fetches new data when needed
function useFetchedPackageSelection(interest: Cloud$Interest) {
  const updatePackageUrl = `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`;
  // ... rest of the API-based implementation
  // (most of the current useShoppingCart implementation)
}

// For PV systems - works with existing data
function useLocalPackageSelection(interest: Cloud$Interest) {
  const [state, dispatch] = useReducer(
    packageReducer,
    createInitialStore(interest)
  );
  // ... rest of the current emulator implementation
  // but renamed to be more descriptive of what it actually does
}

// Main hook that determines which mode to use
export function usePackages(interest: Cloud$Interest) {
  const mainHardwareType = getMainHardwareType(interest);
  const mode = mainHardwareType === 'pv_system' ? 'local' : 'fetch';

  return usePackageSelection({ mode, interest });
}
```

This refactor:
1. Makes it clear we have two different modes of operation rather than one being an "emulator"
2. Removes shopping cart prefixes since that's now the standard
3. Separates concerns clearly between local state management and API-based management
4. Provides a single entry point that handles the routing to appropriate implementation
5. Makes it easier to potentially add new modes in the future if needed

Usage would be simplified to:
```typescript
function SomeComponent() {
  const { 
    selectedPackage,
    availablePackages,
    changePackage,
    // ... other shared properties
  } = usePackages(interest);
}
```

This makes it clearer that we're dealing with two different but equally valid ways of handling packages, rather than one being a temporary emulation of the other. It also makes it easier to eventually migrate PV systems to the fetched implementation when that becomes possible.
also, I think the cache key thing is way overboard. we use SWR for fetching and it caches things for us - I think the developer in question didn't know about this. incorporate a simplified (but correct) way of configuring SWR so that we don't have to maintain our own cache.

```ts web/breeze/components/CalcPage/utils/getPackageCacheKey.ts
import {
  Cloud$Interest,
  Cloud$PackageRequest,
} from '@otovo/shared/types/cloudApi';
import { Cloud$MainHardwareType } from '@otovo/shared/types/cloudEnums';

function hasEVCharger(interest: Cloud$Interest): boolean {
  return (
    interest.active_shopping_cart_package.price.equipment.ev_chargers.length > 0
  );
}

function createPackageRequest(
  mainHardwareType: Cloud$MainHardwareType,
  interest: Cloud$Interest,
): Cloud$PackageRequest {
  const packageSize = interest.active_shopping_cart_package.package_size;

  switch (mainHardwareType) {
    case 'battery_system':
      return {
        main_hardware_type: mainHardwareType,
        battery_package_size: packageSize,
        with_ev_charger: hasEVCharger(interest),
      };
    case 'pv_system':
      return {
        main_hardware_type: mainHardwareType,
        pv_product_name: interest.active_shopping_cart_package.product_name,
        pv_package_size: packageSize,
        with_battery:
          interest.active_shopping_cart_package.price.equipment.batteries
            .length > 0,
        with_ev_charger: hasEVCharger(interest),
      };
    default:
      throw new Error('Unknown main hardware type');
  }
}

export function generateCacheKey(
  selectedShoppingCartPackage: Cloud$PackageRequest,
): string {
  const { main_hardware_type } = selectedShoppingCartPackage;

  if (main_hardware_type === 'battery_system') {
    return `${main_hardware_type}_${selectedShoppingCartPackage.battery_package_size}_${selectedShoppingCartPackage.with_ev_charger}`;
  }

  return (
    `${main_hardware_type}_` +
    `${selectedShoppingCartPackage.pv_product_name}_` +
    `${selectedShoppingCartPackage.pv_package_size}_` +
    `${selectedShoppingCartPackage.with_battery}_` +
    `${selectedShoppingCartPackage.with_ev_charger}`
  );
}

export function getPackageCacheKey(
  mainHardwareType: Cloud$MainHardwareType,
  interest: Cloud$Interest,
): string {
  const packageRequest = createPackageRequest(mainHardwareType, interest);
  return generateCacheKey(packageRequest);
}
```


You're absolutely right. SWR handles caching for us, and we can use its mutation and key generation features instead of managing our own cache. Here's a simplified version using SWR properly:

```typescript
// usePackages.ts
import useSWR, { useSWRConfig } from 'swr'
import { mutate } from 'swr'

// Key generator for SWR
const getPackageKey = (interestId: string, packageRequest: Cloud$PackageRequest) => {
  return [`/web/interests/${interestId}/update_package`, packageRequest]
}

function useFetchedPackageSelection(interest: Cloud$Interest) {
  const { mutate } = useSWRConfig()

  // Use SWR for the main package data
  const { data: packageData, error, isLoading } = useSWR(
    getPackageKey(interest.id, currentPackageRequest),
    ([url, packageRequest]) => fetchPackage(url, packageRequest)
  )

  // For mutations
  const changePackage = async (packageChange: PackageChange) => {
    const newPackageRequest = getPreferredConfiguration({
      packageChange,
      // ... other params
    })

    try {
      // SWR will handle caching for us
      const result = await mutate(
        getPackageKey(interest.id, newPackageRequest),
        fetchPackage(updatePackageUrl, newPackageRequest),
        {
          // Optimistic update if needed
          optimisticData: (currentData) => ({
            ...currentData,
            // update with new package request
          }),
          // Revalidate after mutation
          revalidate: true
        }
      )

      return result
    } catch (error) {
      // Handle error
    }
  }

  return {
    selectedPackage: packageData?.shoppingCartPackage,
    isLoading,
    error,
    changePackage,
    // ... other properties
  }
}

// Fetch function
const fetchPackage = async (url: string, packageRequest: Cloud$PackageRequest) => {
  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(packageRequest),
  })

  if (!response.ok) {
    throw new Error(response.statusText)
  }

  return response.json()
}
```

This approach:
1. Uses SWR's built-in caching mechanism instead of manual cache management
2. Uses proper key generation based on the interest ID and package request
3. Leverages SWR's mutation utilities for updating data
4. Provides loading and error states automatically
5. Allows for optimistic updates if needed
6. Can be configured with global SWR options for revalidation, dedupingInterval, etc.

The key benefits are:
- Less code to maintain
- Automatic cache invalidation
- Built-in revalidation
- Consistent loading states
- Better error handling
- Automatic deduplication of requests

We can also configure global SWR options in our app:

```typescript
// _app.tsx or similar
import { SWRConfig } from 'swr'

function MyApp({ Component, pageProps }) {
  return (
    <SWRConfig 
      value={{
        revalidateOnFocus: false,
        dedupingInterval: 2000,
        // other global config
      }}
    >
      <Component {...pageProps} />
    </SWRConfig>
  )
}
