    }
  )

  // Local implementation
  const handleLocalPackageChange = async (packageChange: PackageChange) => {
    const newConfiguration = getNewConfiguration(packageChange)
    localState[1](selectPackage(newConfiguration))
  }

  // Fetched implementation
  const handleFetchedPackageChange = async (packageChange: PackageChange) => {
    const preferredPackage = getPreferredConfiguration({
      packageChange,
      currentConfiguration: selectedPackage,
      // ... other required params
    })

    await updatePackage(preferredPackage)
  }

  if (mainHardwareType === 'pv_system') {
    const [state, dispatch] = localState

    return {
