};

export type PackageChange =
  | {
      option: 'pv_package_size' | 'battery_package_size';
      value: Cloud$PackageSize;
    }
  | {
      option: 'pv_product_name';
      value: Cloud$ProductName;
    }
  | {
      option: 'with_ev_charger' | 'with_battery';
      value: boolean;
    };

export type ShoppingCartReturn = {
  availableShoppingCartPackages: Cloud$PackageOption[];
  selectedShoppingCartPackage: Cloud$Package;
  selectedFinancingOption: Cloud$FinancingOption;
  surfaceConfigurationList: SurfaceConfiguration[];
  isLoadingPackage: boolean;
  isMutatingPackageOptions: boolean;
  isPackageUpgraded: boolean;
  mainHardwareType: Cloud$MainHardwareType;

  changePackage: (mutation: PackageChange) => Promise<void>;
  toggleSurface: (referenceId: string) => void;
  changePurchaseModel: (purchaseModelCode: Cloud$PurchaseModelCode) => void;
};

export function useShoppingCart(interest: Cloud$Interest): ShoppingCartReturn {
  const updatePackageUrl = `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`;
  const { trigger: triggerPackageMutation } = useSWRMutation(
    updatePackageUrl,
    getPackage,
    {
      onSuccess: (data) => setNewConfiguration(data.packageRequest),
      populateCache: true,
    },
  );
  const [selectedShoppingCartPackage, setSelectedShoppingCartPackage] =
    useState(interest.active_shopping_cart_package);
  const [isLoadingPackage, setIsLoadingPackage] = useState(false);
  const { cache } = useSWRConfig();

  const [mainHardwareType] = useState<Cloud$MainHardwareType>(
    getMainHardwareType(interest),
  );
  const packageOptionsUrl = `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/package_options/`;
  const {
    trigger: triggerPackageOptions,
    data: packageOptionsData,
    isMutating: isMutatingPackageOptions,
  } = useSWRMutation(packageOptionsUrl, getPackageOptions, {});
  useEffect(() => {
    if (!triggerPackageOptions || !mainHardwareType) return;
    if (mainHardwareType !== 'battery_system') return; // TODO: remove when non-battery systems are supported
    triggerPackageOptions(mainHardwareType);
  }, [mainHardwareType, triggerPackageOptions]);

  // Cache the interest shopping cart package
  useEffect(() => {
    if (interest.active_shopping_cart_package && mainHardwareType) {
      const cacheKey = getPackageCacheKey(mainHardwareType, interest);
      const cachedData = cache.get(cacheKey);
      if (!cachedData) {
        cache.set(cacheKey, {
          data: { shoppingCartPackage: interest.active_shopping_cart_package },
        });
      }
    }
  }, [interest, cache, mainHardwareType]);

  const [{ currentConfiguration, previousConfiguration }, setNewConfiguration] =
    useReducer(configurationReducer, initialConfiguration(interest));
  const [purchaseModelCode, setPurchaseModelCode] = useState(
    interest.default_purchase_model,
  );

  // TODO: remove non-shopping cart calculations when all calculations are fetched via the shopping cart API.
  const emulatedHook = useShoppingCartEmulator(interest);
  if (mainHardwareType === 'pv_system') {
    return emulatedHook;
  }

  const availableShoppingCartPackages = packageOptionsData || [];

  const selectedFinancingOption =
    selectedShoppingCartPackage?.price.financing_options.find(
      (f) => f.purchase_model_code === purchaseModelCode,
    ) || selectedShoppingCartPackage?.price.financing_options[0];

  const changePackage = async (packageChange: PackageChange) => {
    const preferredPackage = getPreferredConfiguration({
      packageChange,
      availableConfigurations: availableShoppingCartPackages,
      currentConfiguration,
      previousConfiguration,
    });
    const cacheKey = generateCacheKey(preferredPackage);
    const cachedData = cache.get(cacheKey);

    if (cachedData) {
      setSelectedShoppingCartPackage(cachedData.data.shoppingCartPackage);
      triggerPackageMutation(preferredPackage);
    } else {
      // Set loading state only if we are not using cached data
      setIsLoadingPackage(true);
      const response = await triggerPackageMutation(preferredPackage);
      cache.set(cacheKey, { data: response });
      setSelectedShoppingCartPackage(response.shoppingCartPackage);
      setIsLoadingPackage(false);
    }
  };

  const isPackageUpgraded =
    previousConfiguration?.main_hardware_type === 'pv_system' &&
    currentConfiguration.main_hardware_type === 'pv_system' &&
    !previousConfiguration.with_battery &&
    currentConfiguration.with_battery &&
    previousConfiguration.pv_product_name ===
      currentConfiguration.pv_product_name &&
    previousConfiguration.pv_package_size ===
      currentConfiguration.pv_package_size;

  return {
    selectedShoppingCartPackage,
    selectedFinancingOption,
    availableShoppingCartPackages,
    isLoadingPackage,
    isMutatingPackageOptions: isMutatingPackageOptions,
    mainHardwareType: mainHardwareType,
    changePurchaseModel: (newPurchaseModelCode: Cloud$PurchaseModelCode) => {
      if (
        !selectedShoppingCartPackage?.price.financing_options
          .map((f) => f.purchase_model_code)
          .includes(newPurchaseModelCode)
      ) {
        throw Error(`Invalid purchase model code ${newPurchaseModelCode}`);
      }

      setPurchaseModelCode(newPurchaseModelCode);
      logChoiceSelection({
        choiceLabel: 'purchase model',
        changedTo: newPurchaseModelCode,
        experimentVersion: interest.experiment_version,
      });
    },
    changePackage,
    toggleSurface: () => {}, // Battery has no surfaces to toggle.
    surfaceConfigurationList: [],
    isPackageUpgraded,
  };
}
