```ts web/breeze/stores/Interest/reducer.ts
import { Cloud$Interest, Cloud$Product } from '@otovo/shared/types/cloudApi';
import { SET_PRODUCTS, UPDATE_INTEREST } from './actionTypes';
import { InterestStore } from './type';

export type InterestActionTypes =
  | {
      readonly type: typeof UPDATE_INTEREST;
      readonly interest: Cloud$Interest;
    }
  | {
      readonly type: typeof SET_PRODUCTS;
      readonly products: Cloud$Product[];
    };

export function createInitialInterestStoreState(
  interest: Cloud$Interest,
): InterestStore {
  return {
    interest,
    areAllProductsFetched: false,
  };
}

export default function interestReducer(
  state: InterestStore,
  action: InterestActionTypes,
): InterestStore {
  switch (action.type) {
    case UPDATE_INTEREST:
      return {
        areAllProductsFetched: false,
        interest: action.interest,
      };

    case SET_PRODUCTS:
      return {
        areAllProductsFetched: true,
        interest: {
          ...state.interest,
          products: [...state.interest.products, ...action.products],
        },
      };

    default:
      return action satisfies never;
  }
}
