import { Cloud$Interest } from '@otovo/shared/types/cloudApi';
import isInterestAccepted from './isInterestAccepted';

export default function getPreferredOptions(interest: Cloud$Interest) {
  const isAccepted = isInterestAccepted(interest.status);
  const { active_shopping_cart_package: activeShoppingCartPackage } = interest;

  if (isAccepted && activeShoppingCartPackage) {
    return {
      preferredProductName: activeShoppingCartPackage.product_name,
      preferredPackageSlug: activeShoppingCartPackage.package_size,
      preferredPurchaseModelCode: interest.default_purchase_model,
      preferBatteryPackage:
        activeShoppingCartPackage.price.equipment.batteries.length > 0,
      preferEvChargerPackage:
        activeShoppingCartPackage.price.equipment.ev_chargers.length > 0,
    };
  }
  return {
    // Cloud takes care of removing the invalid "unknown" value during serialization.
    preferredProductName: interest.default_product_classification || null,
    preferredPackageSlug: null,
    preferredPurchaseModelCode: interest.default_purchase_model,
    preferBatteryPackage: interest.prefer_battery_package,
    preferEvChargerPackage: interest.prefer_ev_charger_package,
  };
}
