import { Cloud$Package, Cloud$SpecSurface } from '@otovo/shared/types/cloudApi';

import { Surface$Surface } from '@otovo/shared/types/surfaceTypes';
import { SurfaceConfiguration } from '../type';

function getSpecSurface(
  surfaceId: string,
  selectedPackage: Cloud$Package,
): Cloud$SpecSurface {
  return selectedPackage.price.surfaces.find((s) => s.surface.id === surfaceId);
}

const MAP_DISPLAY_POLYGON_PALETTE = [
  '#0BFF01',
  '#FDFE02',
  '#FE00F6',
  '#011EFE',
  '#13A8FE',
  '#911EB4',
  '#111111',
  '#AAFFC3',
  '#FE0000',
  '#800000',
];

type Args = {
  surface: Surface$Surface;
  index: number;
  selectedPackage: Cloud$Package;
};

export default ({
  surface,
  index,
  selectedPackage,
}: Args): SurfaceConfiguration => {
  const specSurface = getSpecSurface(surface.id, selectedPackage);
  return {
    surfaceId: surface.id,
    isSelected: !!specSurface,
    isFake: surface.is_fake,
    roofing: specSurface
      ? specSurface.roofing
      : surface.default_mounting_surface,
    color:
      MAP_DISPLAY_POLYGON_PALETTE[index % MAP_DISPLAY_POLYGON_PALETTE.length],
    maxNumPanels: surface.max_num_panels || 0,
  };
};
