```typescript
function getInitialState(interest: Cloud$Interest): LocalState {
  const activePackage = interest.active_shopping_cart_package;

  if (!activePackage) {
    throw new Error('No active package found for PV system');
  }

  // Default to the first financing option if none is specified in the interest
  const defaultFinancingOption = activePackage.price.financing_options.find(
    option => option.purchase_model_code === interest.default_purchase_model
  ) || activePackage.price.financing_options[0];

  if (!defaultFinancingOption) {
    throw new Error('No financing options available for package');
  }

  return {
    selectedPackage: activePackage,
    previousPackage: null,
    selectedFinancingOption: defaultFinancingOption,
  };
}
```

This:
1. Uses the `active_shopping_cart_package` as the source of truth
2. Respects the interest's `default_purchase_model` if specified
3. Falls back to the first financing option if no default is specified
4. Has appropriate error handling for edge cases
5. Sets `previousPackage` to null initially (it will be populated when the package changes)

