```tsx web/breeze/components/Interest/InterestRefetchCalculationWrapper.tsx
import { Cloud$Interest } from '@otovo/shared/types/cloudApi';
import { useRouter } from 'next/router';
import { useCallback, useReducer, useState } from 'react';
import useInterest from '../../hooks/useInterest';
import useProducts from '../../hooks/useProducts';
import { setProducts, updateInterest } from '../../stores/Interest/actions';
import interestReducer, {
  createInitialInterestStoreState,
} from '../../stores/Interest/reducer';
import CalcPageWrapper from '../CalcPage/CalcPageWrapper';

type Props = {
  interestId: string;
};

function toUnix(dateStr: string) {
  return new Date(dateStr).getTime();
}

const InterestRefetchCalculationWrapper = ({ interestId }: Props) => {
  const router = useRouter();
  const { query } = router;
  const postActivationPageUrl = `/products/[id]/request-received`;

  router.prefetch(postActivationPageUrl);

  const redirectToPostActivationPage = () => {
    router.push({
      pathname: `/products/[id]/request-received`,
      query,
    });
  };
  const [calcCreatedAtMinimum, setCalcCreatedAtMinimum] = useState(0);

  const pollUntilFunction = useCallback(
    (interest: Cloud$Interest) => {
      return toUnix(interest.calc_created_at) > calcCreatedAtMinimum;
    },
    [calcCreatedAtMinimum],
  );

  const {
    interest,
    mutate: refetchInterest,
    isPolling,
  } = useInterest(interestId, { pollUntilFunction });

  const [state, dispatch] = useReducer(
    interestReducer,
    createInitialInterestStoreState(interest),
  );

  const isRefetched =
    interest.calc_created_at !== state.interest.calc_created_at ||
    interest.status !== state.interest.status;

  if (isRefetched) {
    dispatch(updateInterest(interest));
  }

  function refetchCalc() {
    setCalcCreatedAtMinimum(
      Math.max(calcCreatedAtMinimum, toUnix(interest.calc_created_at)),
    );
    refetchInterest();
  }

  const interestIsReady = !!interest && !isPolling;
  const { products } = useProducts(interestIsReady ? interest : null);

  if (products && !state.areAllProductsFetched) {
    dispatch(setProducts(products));
  }

  return (
    <CalcPageWrapper
      isPolling={isPolling}
      state={state}
      dispatch={dispatch}
      onUpdateSurfacesSuccess={refetchCalc}
      onAcceptCalculation={redirectToPostActivationPage}
    />
  );
};

export default InterestRefetchCalculationWrapper;
