  PackageSelectionReturn,
  PackageChange,
} from '../../../stores/Interest/type';
import { isEvChargerPackage } from '../../../lib/packageUtils';
import { Cloud$PurchaseModelCode } from '@otovo/shared/types/cloudEnums';

async function updatePackage(
  url: string,
  { arg: packageRequest }: { arg: Cloud$PackageRequestBattery_NEW },
) {
  const response = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(packageRequest),
  });

  if (!response.ok) {
    throw new Error('Failed to update package');
  }

  return response.json();
}

function getPackageRequestOptions(
  pkg: Cloud$Package,
): Cloud$PackageOptionBattery_NEW {
  return {
    main_hardware_type: 'battery_system',
    name: pkg.name, // e.g. standard_small
    product_name: pkg.product_name, // Pointer back to the product (e.g. standard)
    package_size: pkg.package_size, // e.g. small, medium, large
    with_ev_charger: isEvChargerPackage(pkg),
    minimum_battery_capacity: pkg.price.equipment.batteries[0]?.capacity || 0,
  };
}

export function useFetchedPackageSelection(
  interest: Cloud$Interest,
): PackageSelectionReturn {
  const availablePackages = interest.products
    .flatMap((p) => p.packages)
    .map(getPackageRequestOptions);
  const productNames = new Set(availablePackages.map((p) => p.product_name));
  const packageNames = new Set(availablePackages.map((p) => p.name));

  const [selectedPackage, setSelectedPackage] = useState<Cloud$Package | null>(
    interest.active_shopping_cart_package,
  );
  const [selectedFinancingOption, setSelectedFinancingOption] = useState(
    interest.active_shopping_cart_package?.price.financing_options.find(
      (option) =>
        option.purchase_model_code === interest.default_purchase_model,
    ) ||
      interest.active_shopping_cart_package?.price.financing_options[0] ||
      null,
  );

  const { trigger: updatePackageMutation, isMutating } = useSWRMutation(
    `${process.env.NEXT_PUBLIC_OTOVOAPI_URL}/web/interests/${interest.id}/update_package/`,
    updatePackage,
    {
      onSuccess: (pkg: Cloud$Package) => {
        setSelectedPackage(pkg);
        setSelectedFinancingOption(
          pkg.price.financing_options.find(
            (o) =>
              o.purchase_model_code ===
              selectedFinancingOption?.purchase_model_code,
          ) || pkg.price.financing_options[0],
        );
      },
    },
  );

  const changePackage = async (request: PackageChange) => {
    if (!selectedPackage) return;

    const currentConfig = getPackageRequestOptions(selectedPackage);
    const newConfiguration: Cloud$PackageRequestBattery_NEW = {
      ...currentConfig,
      [request.option]: request.value,
    };

    await updatePackageMutation(newConfiguration);
  };

  const changePurchaseModel = (code: Cloud$PurchaseModelCode) => {
    if (!selectedPackage) return;

    const newOption = selectedPackage.price.financing_options.find(
      (option) => option.purchase_model_code === code,
    );

    if (newOption) {
      setSelectedFinancingOption(newOption);
    }
  };

  return {
    selectedPackage,
    selectedFinancingOption,
    availablePackages,
    surfaceConfiguration: [], // Battery systems don't have surfaces
    isLoading: false,
    isMutating,
    isPackageUpgraded: false, // Battery systems don't have the upgrade concept
    mainHardwareType: 'battery_system',
    changePackage,
    changePurchaseModel,
    productNames,
    packageNames,
  };
}
