import { Cloud$Interest, Cloud$Package } from '@otovo/shared/types/cloudApi';
import { SurfaceConfiguration } from '../stores/Interest/type';
import { useReducer } from 'react';
import surfaceConfigurationMapper from '../stores/Interest/utils/surfaceConfigurationMapper';
