type SurfaceState = {
  configurations: SurfaceConfiguration[];
};

type SurfaceAction = {
  type: 'TOGGLE_SURFACE';
  surfaceId: string;
};

function surfaceReducer(state: SurfaceState, action: SurfaceAction): SurfaceState {
  switch (action.type) {
    case 'TOGGLE_SURFACE':
      return {
        configurations: state.configurations.map((config) =>
          config.surfaceId === action.surfaceId
            ? { ...config, isSelected: !config.isSelected }
            : config
        ),
      };
    default:
      return state;
  }
}

function getInitialSurfaceConfigurations(
  interest: Cloud$Interest,
  selectedPackage: Cloud$Package,
): SurfaceConfiguration[] {
  return interest.available_surfaces
    .filter(validateScore)
    .map((surface, index) =>
      surfaceConfigurationMapper({
        surface,
        index,
        selectedPackage,
      })
    );
}

export function useSurfaceConfiguration(
  interest: Cloud$Interest,
  selectedPackage: Cloud$Package,
) {
  const [state, dispatch] = useReducer(surfaceReducer, {
    configurations: getInitialSurfaceConfigurations(interest, selectedPackage),
  });

  const toggleSurface = (surfaceId: string) => {
    dispatch({ type: 'TOGGLE_SURFACE', surfaceId });
  };

  return {
    surfaceConfiguration: state.configurations,
    toggleSurface,
  };
}
