For this case, SWR's built-in cache is probably the simplest solution. We can use a consistent cache key and let SWR handle the state sharing:

```typescript
// hooks/usePackages.ts
import useSWR from 'swr';
import { Cloud$Interest } from '@otovo/shared/types/cloudApi';
import { PackageSelectionReturn } from '../stores/Interest/type';
import { getMainHardwareType } from '../stores/Interest/utils/getMainHardwareType';
import { useLocalPackageSelection } from './useLocalPackageSelection';
import { useFetchedPackageSelection } from './useFetchedPackageSelection';
import useProducts from '../hooks/useProducts';

// Create a consistent cache key for the package selection state
const getPackageKey = (interestId: string) => 
  `package-selection/${interestId}`;

export function usePackages(interest: Cloud$Interest): PackageSelectionReturn {
  const { products: additionalProducts } = useProducts(interest);
  const mainHardwareType = getMainHardwareType(interest);

  const { data: packageSelection, mutate } = useSWR(
    getPackageKey(interest.id),
    () => {
      const strategy = mainHardwareType === 'pv_system' ? 'local' : 'fetched';
      return strategy === 'local' 
        ? useLocalPackageSelection(interest, additionalProducts)
        : useFetchedPackageSelection(interest);
    },
    {
      revalidateOnFocus: false, // Prevent unnecessary revalidation
      revalidateIfStale: false,
    }
  );

  return packageSelection;
}
```

Now any component using `usePackages` with the same interest ID will share the same state through SWR's cache. This approach:

1. Is very simple to implement
2. Leverages SWR's built-in caching
3. Handles revalidation automatically
4. Doesn't require additional state management libraries
5. Is React concurrent mode safe

