Ah yes, you're absolutely right! Calling hooks inside the SWR fetcher function would break the rules of hooks. A better approach would be to use React's Context API combined with a reducer. Here's a simple implementation:

```typescript
// hooks/packages/PackageContext.tsx
import { createContext, useContext, useReducer, PropsWithChildren } from 'react';
import { Cloud$Interest, Cloud$Package } from '@otovo/shared/types/cloudApi';
import { PackageSelectionReturn } from '../stores/Interest/type';

type PackageState = Record<string, PackageSelectionReturn>;

type PackageAction = {
  type: 'UPDATE_PACKAGE_SELECTION';
  interestId: string;
  selection: PackageSelectionReturn;
};

const PackageContext = createContext<{
  state: PackageState;
  dispatch: React.Dispatch<PackageAction>;
} | null>(null);

function packageReducer(state: PackageState, action: PackageAction): PackageState {
  switch (action.type) {
    case 'UPDATE_PACKAGE_SELECTION':
      return {
        ...state,
        [action.interestId]: action.selection,
      };
    default:
      return state;
  }
}

export function PackageProvider({ children }: PropsWithChildren) {
  const [state, dispatch] = useReducer(packageReducer, {});

  return (
    <PackageContext.Provider value={{ state, dispatch }}>
      {children}
    </PackageContext.Provider>
  );
}

export function usePackages(interest: Cloud$Interest): PackageSelectionReturn {
  const context = useContext(PackageContext);
  if (!context) {
    throw new Error('usePackages must be used within a PackageProvider');
  }

  const { state, dispatch } = context;
  const { products: additionalProducts } = useProducts(interest);
  const mainHardwareType = getMainHardwareType(interest);

  // Use hooks unconditionally
  const localResult = useLocalPackageSelection(interest, additionalProducts);
  const fetchedResult = useFetchedPackageSelection(interest);

  const selection = mainHardwareType === 'pv_system' ? localResult : fetchedResult;

  // Update shared state when selection changes
  useEffect(() => {
    dispatch({
      type: 'UPDATE_PACKAGE_SELECTION',
      interestId: interest.id,
      selection,
    });
  }, [selection, interest.id, dispatch]);

  // Return either cached state or new selection
  return state[interest.id] || selection;
}
```

