  const newSelection = mainHardwareType === 'pv_system' ? localResult : fetchedResult;

  // Update shared state when selection changes
  useEffect(() => {
    setSelection(newSelection);
  }, [newSelection, setSelection]);

  // Return either cached selection or new selection
  return selection || newSelection;
}
