```typescript
// hooks/packages/usePackages.ts
import useSWR, { mutate } from 'swr';
import { Cloud$Interest } from '@otovo/shared/types/cloudApi';
import { PackageState } from '../../../stores/Interest/type';

const getPackageKey = (interestId: string) => `package-state/${interestId}`;

export function usePackages(interest: Cloud$Interest): PackageState {
  const { products: additionalProducts } = useProducts(interest);
  const mainHardwareType = getMainHardwareType(interest);

  // Use SWR without a fetcher
  const { data: pkgState } = useSWR<PackageState>(
    getPackageKey(interest.id),
    null, // No fetcher function
    {
      fallbackData: null, // Initial value
      revalidateOnFocus: false,
      revalidateOnReconnect: false,
    }
  );

  const localResult = useLocalPackageSelection(interest, additionalProducts);
  const fetchedResult = useFetchedPackageSelection(interest);

  const newState = mainHardwareType === 'pv_system' ? localResult : fetchedResult;

  useEffect(() => {
    mutate(getPackageKey(interest.id), newState);
  }, [interest.id, newState]);

  return pkgState || newState;
}
```

This gives us:
1. SWR's built-in cache management
2. Automatic state sharing between components
3. No need for context or providers
4. All the benefits of SWR's cache invalidation when we want it
5. Much simpler implementation

