import { Cloud$PurchaseModelCode } from '@otovo/shared/types/cloudEnums';
import {
  Cloud$FinancingOption,
  Cloud$Interest,
  Cloud$Package,
  Cloud$PackageOptionPV_NEW,
  Cloud$PackageRequestPV_NEW,
  Cloud$Product,
} from '@otovo/shared/types/cloudApi';
import { useSurfaceConfiguration } from './useSurfaceConfiguration';

type LocalState = {
  selectedPackage: Cloud$Package;
  previousPackage: Cloud$Package | null;
  selectedFinancingOption: Cloud$FinancingOption;
};

type LocalAction =
  | { type: 'CHANGE_PACKAGE'; package: Cloud$Package }
  | { type: 'CHANGE_PURCHASE_MODEL'; code: Cloud$PurchaseModelCode }
  | { type: 'TOGGLE_SURFACE'; surfaceId: string };

function localReducer(state: LocalState, action: LocalAction): LocalState {
  switch (action.type) {
    case 'CHANGE_PACKAGE':
      return {
        ...state,
        previousPackage: state.selectedPackage,
        selectedPackage: action.package,
        selectedFinancingOption: action.package.price.financing_options[0],
      };

    case 'CHANGE_PURCHASE_MODEL': {
      const newFinancingOption =
        state.selectedPackage.price.financing_options.find(
          (option) => option.purchase_model_code === action.code,
        );

      if (!newFinancingOption) {
        throw new Error(`Invalid purchase model code: ${action.code}`);
      }

      return {
        ...state,
        selectedFinancingOption: newFinancingOption,
      };
    }

    default:
      return state;
  }
}

function getPackageRequestOptions(
  pkg: Cloud$Package,
): Cloud$PackageOptionPV_NEW {
  return {
    main_hardware_type: 'pv_system',
    name: pkg.name, // e.g. standard_small
    product_name: pkg.product_name, // Pointer back to the product (e.g. standard)
    package_size: pkg.package_size, // e.g. small, medium, large
    with_battery: isBatteryPackage(pkg),
    with_ev_charger: isEvChargerPackage(pkg),
    number_of_panels: pkg.price.num_panels,
    nominal_system_power: pkg.price.nominal_system_power,
    nominal_panel_power: pkg.price.equipment.panels.nominal_panel_power,
  };
}

function getAvailablePackages(
  products: Cloud$Product[],
): Cloud$PackageOptionPV_NEW[] {
  return products.flatMap((p) => p.packages).map(getPackageRequestOptions);
}

function getInitialState(interest: Cloud$Interest): LocalState {
  const activePackage = interest.active_shopping_cart_package;

  if (!activePackage) {
    throw new Error('No active package found for PV system');
  }

  // Default to the first financing option if none is specified in the interest
  const defaultFinancingOption =
    activePackage.price.financing_options.find(
      (option) =>
        option.purchase_model_code === interest.default_purchase_model,
    ) || activePackage.price.financing_options[0];

  if (!defaultFinancingOption) {
    throw new Error('No financing options available for package');
  }

  return {
    selectedPackage: activePackage,
    previousPackage: null,
    selectedFinancingOption: defaultFinancingOption,
  };
}

export function useLocalPackageSelection(
  interest: Cloud$Interest,
  additionalProducts?: Cloud$Product[],
): PackageState {
  const [state, dispatch] = useReducer(localReducer, interest, getInitialState);
  const allProducts = interest.products;
  const availablePackages = getAvailablePackages(allProducts);

  const { surfaceConfiguration, toggleSurface } = useSurfaceConfiguration(
    interest,
    state.selectedPackage,
  );

  const productNames = new Set(availablePackages.map((p) => p.product_name));
  const packageNames = new Set(availablePackages.map((p) => p.name));

  // Add any new products that we don't already have in the initial interest response
  if (additionalProducts?.length) {
    additionalProducts
      .filter((p) => !productNames.has(p.name))
      .forEach((p) => allProducts.push(p));
  }

  const changePackage = async (request: PackageChange) => {
    const currentRequest = getPackageRequestOptions(state.selectedPackage);

    const newConfiguration: Cloud$PackageRequestPV_NEW = {
      ...currentRequest,
      [request.option]: request.value,
    };

    // Find matching package in products
    const newPackage = interest.products
      .flatMap((p) => p.packages)
      .find(
        (p) =>
          p.product_name === newConfiguration.product_name &&
          p.package_size === newConfiguration.package_size &&
          isBatteryPackage(p) === newConfiguration.with_battery &&
          isEvChargerPackage(p) === newConfiguration.with_ev_charger,
      );

    if (!newPackage) {
      throw new Error('No matching package found for configuration');
    }

    dispatch({ type: 'CHANGE_PACKAGE', package: newPackage });
  };

  const changePurchaseModel = (code: Cloud$PurchaseModelCode) => {
    dispatch({ type: 'CHANGE_PURCHASE_MODEL', code });
  };

  const isPackageUpgraded =
    state.previousPackage &&
    !isBatteryPackage(state.previousPackage) &&
    isBatteryPackage(state.selectedPackage) &&
    state.previousPackage.product_name === state.selectedPackage.product_name &&
    state.previousPackage.package_size === state.selectedPackage.package_size;

  return {
    selectedPackage: state.selectedPackage,
    selectedFinancingOption: state.selectedFinancingOption,
    availablePackages: availablePackages,
    surfaceConfiguration: surfaceConfiguration,
    isLoading: false, // Local selection is always synchronous
    isMutating: false,
    isPackageUpgraded,
    mainHardwareType: 'pv_system',
    changePackage,
    changePurchaseModel,
    toggleSurface,
    productNames,
    packageNames,
  };
}
